# ✅ Backtracking: Explore all solutions, backtrack on dead-end
def solve_sudoku(grid, row, col):
    # ✅ Base case: all cells filled
    if row == 9 and col == 9:
        return True

    # ✅ Move to next cell
    if grid[row][col] != 0:
        return solve_sudoku(grid, row + (col + 1) // 9, (col + 1) % 9)

    # ✅ Try all values 1-9
    for num in range(1, 10):
        if is_valid(grid, row, col, num):
            grid[row][col] = num  # ✅ Place number
            if solve_sudoku(grid, row + (col + 1) // 9, (col + 1) % 9):
                return True  # ✅ Solution found
            grid[row][col] = 0  # ✅ Backtrack: undo [web:189][web:191]

    return False  # ❌ No solution [web:189]

