# ✅ Recursive directory traversal (search for files)
import os

def find_files(directory, pattern):
    matching_files = []

    for item in os.listdir(directory):
        path = os.path.join(directory, item)

        if os.path.isfile(path):  # ✅ File (base case)
            if pattern in item:
                matching_files.append(path)
        elif os.path.isdir(path):  # ✅ Directory (recursive case)
            matching_files.extend(find_files(path, pattern))  # ✅ Recurse [web:189]

    return matching_files

